// Pull both ensures-conjuncts that bind to `self_@.un_acked_messages(src@)`
// into proof context so z3 can line up the two `forall`/set-builder
// instantiations from the r1- and r2-runs.
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@) == self_@.un_acked_messages(src@));
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@) == self_@.un_acked_messages(src@));
assert(self_@.un_acked_messages(src@) == r1@.map_values(|p: CPacket| p@).to_set());
assert(self_@.un_acked_messages(src@) == r2@.map_values(|p: CPacket| p@).to_set());

// Transitively close the abstract/set views over r1 and r2 against the
// shared `un_acked_messages(src@)` anchor.
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@)
    == abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@));
assert(r1@.map_values(|p: CPacket| p@).to_set()
    == r2@.map_values(|p: CPacket| p@).to_set());

// Pull the remaining per-result validity conjuncts in, so any
// `det_*_equal` clause that mentions them sees identical witnesses
// for both r1 and r2.
assert(outbound_packet_seq_is_valid(r1@));
assert(outbound_packet_seq_is_valid(r2@));
assert(outbound_packet_seq_has_correct_srcs(r1@, src@));
assert(outbound_packet_seq_has_correct_srcs(r2@, src@));
assert(CSingleDelivery::packets_are_valid_messages(r1@));
assert(CSingleDelivery::packets_are_valid_messages(r2@));
